let RECORDS = [];
let editingId = null;

/* ==================== CONTROLE DE SESSÃO E LOGIN ==================== */
document.addEventListener('DOMContentLoaded', function() {
    const loginForm = document.getElementById('loginForm');
    if (loginForm) {
        loginForm.addEventListener('submit', executarLogin);
        const primeiroAcessoForm = document.getElementById('primeiroAcessoForm');
        if (primeiroAcessoForm) primeiroAcessoForm.addEventListener('submit', executarDefinirSenha);
        const btnVoltar = document.getElementById('btnVoltarLogin');
        if (btnVoltar) btnVoltar.addEventListener('click', voltarParaLogin);
        return;
    }

    const usuarioLogado = JSON.parse(localStorage.getItem('arquivista_user') || 'null');
    if (!usuarioLogado) {
        window.location.href = 'login.html';
        return;
    }

    if (document.getElementById('userBadge')) {
        document.getElementById('userBadge').textContent = `👤 ${usuarioLogado.nome}`;
        inicializarSistema();
    }
});

function checarConfig(){
    if(!CONFIG.API_URL || CONFIG.API_URL.includes('COLE_AQUI')){
        return false;
    }
    return true;
}

let usuarioEmPrimeiroAcesso = '';

async function executarLogin(e) {
    e.preventDefault();
    const usuario = document.getElementById('usuario').value.trim();
    const senha = document.getElementById('senha').value;
    const errorMsg = document.getElementById('errorMsg');
    const btn = document.getElementById('btnEntrar');

    if(!checarConfig()){
        errorMsg.textContent = '⚠️ Configure a API_URL em config.js antes de usar o sistema.';
        return;
    }

    errorMsg.textContent = '';
    btn.disabled = true;
    btn.textContent = 'Validando…';

    try {
        const response = await fetch(CONFIG.API_URL, {
            method: 'POST',
            body: JSON.stringify({ action: 'login', usuario, senha })
        });
        const data = await response.json();

        if (data.success) {
            entrarNoSistema(data.usuario, data.token);
        } else if (data.primeiroAcesso) {
            usuarioEmPrimeiroAcesso = usuario;
            document.getElementById('paUsuarioLabel').textContent = usuario;
            document.getElementById('loginForm').style.display = 'none';
            document.getElementById('primeiroAcessoForm').style.display = 'block';
            btn.disabled = false;
            btn.textContent = 'Acessar sistema';
        } else {
            errorMsg.textContent = '❌ ' + (data.message || 'Usuário ou senha inválidos.');
            btn.disabled = false;
            btn.textContent = 'Acessar sistema';
        }
    } catch (error) {
        errorMsg.textContent = '❌ Não foi possível conectar ao servidor central. Verifique a API_URL em config.js e a implantação do Apps Script.';
        btn.disabled = false;
        btn.textContent = 'Acessar sistema';
    }
}

async function executarDefinirSenha(e) {
    e.preventDefault();
    const novaSenha = document.getElementById('paNovaSenha').value;
    const confirmar = document.getElementById('paConfirmarSenha').value;
    const errorMsg = document.getElementById('errorMsg');
    const btn = document.getElementById('btnDefinirSenha');

    errorMsg.textContent = '';
    if (novaSenha.length < 6) {
        errorMsg.textContent = '❌ A senha precisa ter pelo menos 6 caracteres.';
        return;
    }
    if (novaSenha !== confirmar) {
        errorMsg.textContent = '❌ As senhas digitadas não coincidem.';
        return;
    }

    btn.disabled = true;
    btn.textContent = 'Salvando…';

    try {
        const response = await fetch(CONFIG.API_URL, {
            method: 'POST',
            body: JSON.stringify({ action: 'definirSenha', usuario: usuarioEmPrimeiroAcesso, novaSenha })
        });
        const data = await response.json();

        if (data.success) {
            entrarNoSistema(data.usuario, data.token);
        } else {
            errorMsg.textContent = '❌ ' + (data.message || 'Não foi possível definir a senha.');
            btn.disabled = false;
            btn.textContent = 'Criar senha e entrar';
        }
    } catch (error) {
        errorMsg.textContent = '❌ Não foi possível conectar ao servidor central.';
        btn.disabled = false;
        btn.textContent = 'Criar senha e entrar';
    }
}

function voltarParaLogin() {
    document.getElementById('primeiroAcessoForm').style.display = 'none';
    document.getElementById('loginForm').style.display = 'block';
    document.getElementById('errorMsg').textContent = '';
}

function entrarNoSistema(usuarioObj, token) {
    localStorage.setItem('arquivista_user', JSON.stringify(usuarioObj));
    localStorage.setItem('arquivista_token', token);
    const stamp = document.getElementById('stampSeal');
    if(stamp){
        stamp.classList.add('stamped');
        setTimeout(()=>{ window.location.href = 'index.html'; }, 650);
    } else {
        window.location.href = 'index.html';
    }
}

function logout() {
    localStorage.removeItem('arquivista_user');
    localStorage.removeItem('arquivista_token');
    window.location.href = 'login.html';
}

/* ==================== INICIALIZAÇÃO ==================== */
async function inicializarSistema() {
    vincularEventosUI();
    bindAutocomplete();
    bindDataLimiteAno();
    await carregarDadosServidor();
}

async function carregarDadosServidor() {
    const emptyState = document.getElementById('emptyState');
    if(!checarConfig()){
        if(emptyState){
            emptyState.style.display = 'block';
            emptyState.innerHTML = `<div class="big">Backend não configurado</div><div>Defina CONFIG.API_URL em config.js com a URL do seu Apps Script implantado.</div>`;
        }
        return;
    }
    if(emptyState){
        emptyState.style.display = 'block';
        emptyState.innerHTML = `<div class="big">Carregando acervo central…</div>`;
    }
    try {
        const token = localStorage.getItem('arquivista_token') || '';
        const response = await fetch(`${CONFIG.API_URL}?action=obterDocumentos&token=${encodeURIComponent(token)}`);
        const data = await response.json();
        if (data.success) {
            RECORDS = data.documentos || [];
            renderAll();
        } else if (data.sessaoInvalida) {
            showToast('Sua sessão expirou. Faça login novamente.');
            setTimeout(logout, 1500);
        } else {
            showToast('Erro ao carregar acervo: ' + (data.message||''));
        }
    } catch(e) {
        showToast('Erro de conexão ao baixar o acervo central.');
        if(emptyState){
            emptyState.innerHTML = `<div class="big">Não foi possível conectar ao servidor</div><div>Confira a URL em config.js e se o Apps Script está implantado como "Qualquer pessoa".</div>`;
        }
    }
}

function vincularEventosUI() {
    document.querySelectorAll('.tab').forEach(t=> t.addEventListener('click', ()=>switchView(t.dataset.view)));
    document.getElementById('btnNovo').addEventListener('click', ()=>openModal(null));
    document.getElementById('btnCancelar').addEventListener('click', closeModal);
    document.getElementById('btnSalvar').addEventListener('click', salvarFormulario);
    document.getElementById('btnExcluir').addEventListener('click', deletarRegistro);
    document.getElementById('searchRegistros').addEventListener('input', renderRegistros);
    document.getElementById('filterDestinacao').addEventListener('change', renderRegistros);
    document.getElementById('filterStatus').addEventListener('change', renderRegistros);
    document.getElementById('searchTTD').addEventListener('input', (e)=>renderTTDTree(e.target.value));
    document.getElementById('btnExportar').addEventListener('click', exportarParaExcel);
    document.getElementById('overlay').addEventListener('click', (e)=>{ if(e.target.id==='overlay') closeModal(); });
}

/* ==================== LÓGICA ARQUIVÍSTICA ==================== */
function parseYears(str){
  if(!str) return null;
  const m = String(str).match(/(\d+)\s*anos?/i);
  return m ? parseInt(m[1],10) : null;
}
function addYears(dateStr, years){
  if(!dateStr || years==null) return '';
  const d = new Date(dateStr+'T00:00:00');
  if(isNaN(d)) return '';
  d.setFullYear(d.getFullYear()+years);
  return d.toISOString().slice(0,10);
}
function computeDataLimite(codigo, dataRegistro){
  const entry = TTD_MAP[(codigo||'').toUpperCase().trim()];
  if(!entry || !dataRegistro) return '';
  let anos = parseYears(entry.prazo_corrente);
  if(anos==null) anos = parseYears(entry.prazo_intermediario);
  if(anos==null) return '';
  return addYears(dataRegistro, anos);
}
function statusOf(dataLimite){
  if(!dataLimite) return {key:'ok', label:'Sem data', days:null};
  const today = new Date(); today.setHours(0,0,0,0);
  const ymd = String(dataLimite).slice(0,10);
  const lim = new Date(ymd+'T00:00:00');
  if(isNaN(lim)) return {key:'ok', label:'Sem data', days:null};
  const days = Math.round((lim-today)/86400000);
  if(days<0) return {key:'vencido', label:`Vencido há ${Math.abs(days)}d`, days};
  if(days<=90) return {key:'avencer', label:`Vence em ${days}d`, days};
  return {key:'ok', label:'No prazo', days};
}
function stampClassForDestinacao(dest){
  if(!dest) return 'ok';
  const d = dest.toLowerCase();
  if(d.includes('permanente')) return 'permanente';
  if(d.includes('elimina')) return 'eliminacao';
  return 'ok';
}
function anoOf(dataStr){
  if(!dataStr) return '';
  return String(dataStr).slice(0,4);
}
function fmtDataBR(dataStr){
  if(!dataStr) return '';
  const ymd = String(dataStr).slice(0,10);
  const m = ymd.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if(!m) return ymd;
  return `${m[3]}/${m[2]}/${m[1]}`;
}

function renderAll(){
  renderRegistros();
  renderPainel();
  renderTTDTree();
}

function filteredRecords(){
  const q = (document.getElementById('searchRegistros').value||'').toLowerCase().trim();
  const destF = document.getElementById('filterDestinacao').value;
  const statF = document.getElementById('filterStatus').value;
  return RECORDS.filter(r=>{
    if(q){
      const hay = [r.caixa,r.codigo,r.classificacao,r.referencia,r.processo].join(' ').toLowerCase();
      if(!hay.includes(q)) return false;
    }
    if(destF && r.destinacao!==destF) return false;
    if(statF && statusOf(r.dataLimite).key!==statF) return false;
    return true;
  });
}

function renderRegistros(){
  const tbody = document.getElementById('tblRegistros');
  const list = filteredRecords();
  const emptyState = document.getElementById('emptyState');
  emptyState.style.display = list.length === 0 ? 'block' : 'none';
  if(list.length === 0) {
      emptyState.innerHTML = RECORDS.length === 0
        ? `<div class="big">Nenhum registro ainda</div><div>Crie um novo registro para começar.</div>`
        : `<div class="big">Nenhum registro encontrado</div><div>Refine sua busca ou limpe os filtros.</div>`;
  }
  tbody.innerHTML = list.map(r=>{
    const st = statusOf(r.dataLimite);
    const destStamp = stampClassForDestinacao(r.destinacao);
    return `<tr data-id="${r.id}">
      <td class="mono">${esc(r.caixa||'—')}</td>
      <td><span class="codigo-chip">${esc(r.codigo||'—')}</span></td>
      <td>${esc(r.classificacao||'')}</td>
      <td>${esc(r.referencia||'')}</td>
      <td class="mono">${esc(r.processo||'—')}</td>
      <td class="mono">${anoOf(r.dataLimite)||'—'}</td>
      <td>${esc(r.prazoCorrente||'—')}</td>
      <td>${esc(r.prazoIntermediario||'—')}</td>
      <td><span class="stamp ${destStamp}">${esc(r.destinacao||'—')}</span></td>
      <td>${esc(r.localizacao||'—')}</td>
      <td class="mono">${fmtDataBR(r.dataRegistro)||'—'}</td>
      <td><span class="stamp ${st.key}">${st.label}</span></td>
    </tr>`;
  }).join('');
  tbody.querySelectorAll('tr').forEach(tr=>{
    tr.addEventListener('click', ()=> openModal(tr.dataset.id));
  });
}

function renderPainel(){
  const total = RECORDS.length;
  const permanente = RECORDS.filter(r=>stampClassForDestinacao(r.destinacao)==='permanente').length;
  const eliminacao = RECORDS.filter(r=>stampClassForDestinacao(r.destinacao)==='eliminacao').length;
  const vencidos = RECORDS.filter(r=>statusOf(r.dataLimite).key==='vencido').length;
  const grid = document.getElementById('statGrid');
  grid.innerHTML = `
    <div class="stat-card"><div class="num">${total}</div><div class="lbl">TOTAL DE REGISTROS</div></div>
    <div class="stat-card sage"><div class="num">${permanente}</div><div class="lbl">GUARDA PERMANENTE</div></div>
    <div class="stat-card amber"><div class="num">${eliminacao}</div><div class="lbl">ELIMINAÇÃO PREVISTA</div></div>
    <div class="stat-card rust"><div class="num">${vencidos}</div><div class="lbl">PRAZOS VENCIDOS</div></div>
  `;
  const upcoming = RECORDS
    .map(r=>({r, st:statusOf(r.dataLimite)}))
    .filter(x=>x.st.days!=null && x.st.days>=0 && x.st.days<=90)
    .sort((a,b)=>a.st.days-b.st.days);
  document.getElementById('tblVencimentos').innerHTML = upcoming.length ? upcoming.map(x=>`
    <tr><td class="mono">${esc(x.r.caixa||'—')}</td><td><span class="codigo-chip">${esc(x.r.codigo||'—')}</span></td>
    <td>${esc(x.r.classificacao||'')}</td><td class="mono">${anoOf(x.r.dataLimite)}</td>
    <td><span class="stamp avencer">${x.st.days} dias</span></td></tr>`).join('')
    : `<tr><td colspan="5" style="color:var(--paper-dim); padding:20px 14px;">Nenhum prazo vencendo nos próximos 90 dias.</td></tr>`;
}

/* ==================== TABELA DE TEMPORALIDADE ==================== */
function renderTTDTree(filterQ){
  const q = (filterQ||'').toLowerCase().trim();
  const container = document.getElementById('ttdTree');
  if(q){
    let items = TTD_DATA.filter(d => d.codigo.toLowerCase().includes(q) || d.descritor.toLowerCase().includes(q));
    container.innerHTML = items.filter(d=>d.prazo_corrente||d.prazo_intermediario||d.destinacao).map(rowHtml).join('') || emptyTTD();
    container.querySelectorAll('.ttd-item').forEach(bindTTDClick);
    return;
  }
  let html = '';
  let openGroup = false;
  TTD_DATA.forEach(d=>{
    const isEntry = !!(d.prazo_corrente || d.prazo_intermediario || d.destinacao);
    if(!isEntry){
      if(openGroup) html += '</div>';
      html += `<div class="ttd-group"><div class="ttd-head" data-toggle="1"><span class="code">${esc(d.codigo)}</span><span>${esc(d.descritor)}</span></div><div class="ttd-children">`;
      openGroup = true;
    } else {
      html += rowHtml(d);
    }
  });
  if(openGroup) html += '</div>';
  container.innerHTML = html || emptyTTD();
  container.querySelectorAll('.ttd-head').forEach(h=>{
    h.addEventListener('click', ()=>{
      h.nextElementSibling.classList.toggle('open');
    });
  });
  container.querySelectorAll('.ttd-item').forEach(bindTTDClick);
}
function rowHtml(d){
  const stamp = stampClassForDestinacao(d.destinacao);
  return `<div class="ttd-item" data-code="${esc(d.codigo)}">
    <span class="code">${esc(d.codigo)}</span>
    <span class="desc">${esc(d.descritor)}
      <div class="hint">Corrente: ${esc(d.prazo_corrente||'—')} (${esc(d.evento_corrente||'—')}) · Intermediário: ${esc(d.prazo_intermediario||'—')} (${esc(d.evento_intermediario||'—')})</div>
    </span>
    <span class="dest"><span class="stamp ${stamp}">${esc(d.destinacao||'—')}</span></span>
  </div>`;
}
function emptyTTD(){ return `<div class="empty-state"><div class="big">Nenhum código encontrado</div></div>`; }
function bindTTDClick(el){
  el.addEventListener('click', ()=>{
    openModal(null, el.dataset.code);
    switchView('registros');
  });
}

/* ==================== MODAL / FORMULÁRIO ==================== */
function openModal(id, prefillCodigo){
  editingId = id || null;
  document.getElementById('modalTitle').textContent = id ? 'Editar registro' : 'Novo registro';
  document.getElementById('btnExcluir').style.display = id ? 'inline-flex' : 'none';
  const r = id ? RECORDS.find(x=>x.id===id) : null;
  document.getElementById('fCodigo').value = r ? r.codigo : (prefillCodigo||'');
  document.getElementById('fCaixa').value = r ? r.caixa : '';
  document.getElementById('fProcesso').value = r ? r.processo : '';
  document.getElementById('fReferencia').value = r ? r.referencia : '';
  document.getElementById('fDataRegistro').value = r ? r.dataRegistro : new Date().toISOString().slice(0,10);
  document.getElementById('fDataLimite').value = r ? r.dataLimite : '';
  const fPrazoEl = document.getElementById('fPrazoCorrente');
  fPrazoEl.value = r ? (r.prazoCorrente||'') : '';
  delete fPrazoEl.dataset.userEdited;
  const fPrazoIntEl = document.getElementById('fPrazoIntermediario');
  fPrazoIntEl.value = r ? (r.prazoIntermediario||'') : '';
  delete fPrazoIntEl.dataset.userEdited;
  const fDestEl = document.getElementById('fDestinacao');
  fDestEl.value = r ? (r.destinacao||'') : '';
  delete fDestEl.dataset.userEdited;
  document.getElementById('fLocalizacao').value = r ? r.localizacao : '';
  document.getElementById('fEstado').value = r ? (r.estado||'') : '';
  document.getElementById('fTermo').value = r ? r.termo : '';
  updateTTDPreview();
  if(!r) computeAndFillDataLimite();
  syncDataLimiteAnoFromDate();
  document.getElementById('overlay').classList.add('active');
  document.getElementById('acList').style.display='none';
}
function closeModal(){ document.getElementById('overlay').classList.remove('active'); }

function updateTTDPreview(){
  const codigo = document.getElementById('fCodigo').value.trim().toUpperCase();
  const entry = TTD_MAP[codigo];
  const prev = document.getElementById('ttdPreview');
  if(!entry){ prev.style.display='none'; return; }
  prev.style.display='block';
  const stamp = stampClassForDestinacao(entry.destinacao);
  prev.innerHTML = `
    <div class="row"><span class="lbl">Classificação</span><span class="val">${esc(entry.descritor)}</span></div>
    <div class="row"><span class="lbl">Arquivo corrente</span><span class="val">${esc(entry.prazo_corrente||'—')} · ${esc(entry.evento_corrente||'—')}</span></div>
    <div class="row"><span class="lbl">Arquivo intermediário</span><span class="val">${esc(entry.prazo_intermediario||'—')} · ${esc(entry.evento_intermediario||'—')}</span></div>
    <div class="row"><span class="lbl">Destinação final</span><span class="val"><span class="stamp ${stamp}">${esc(entry.destinacao||'—')}</span></span></div>
    ${entry.observacoes ? `<div class="row" style="margin-top:8px;"><span class="lbl">Obs.</span></div><div style="color:var(--paper-dim); font-size:12px;">${esc(entry.observacoes)}</div>` : ''}
  `;
}
function computeAndFillDataLimite(){
  const codigo = document.getElementById('fCodigo').value.trim();
  const dataRegistro = document.getElementById('fDataRegistro').value;
  const calc = computeDataLimite(codigo, dataRegistro);
  if(calc) document.getElementById('fDataLimite').value = calc;
  syncDataLimiteAnoFromDate();
  const entry = TTD_MAP[codigo.toUpperCase()];
  const fPrazo = document.getElementById('fPrazoCorrente');
  if(entry && fPrazo && !fPrazo.dataset.userEdited){
    fPrazo.value = entry.prazo_corrente || '';
  }
  const fPrazoInt = document.getElementById('fPrazoIntermediario');
  if(entry && fPrazoInt && !fPrazoInt.dataset.userEdited){
    fPrazoInt.value = entry.prazo_intermediario || '';
  }
  const fDest = document.getElementById('fDestinacao');
  if(entry && fDest && !fDest.dataset.userEdited){
    fDest.value = entry.destinacao || '';
  }
}

/* ==================== DATA-LIMITE: SELEÇÃO SÓ POR ANO ==================== */
function populateDataLimiteAnoOptions(){
  const sel = document.getElementById('fDataLimiteAno');
  if(!sel || sel.dataset.populated) return;
  const anoAtual = new Date().getFullYear();
  let opts = '<option value="">—</option>';
  for(let a = anoAtual - 10; a <= anoAtual + 60; a++){
    opts += `<option value="${a}">${a}</option>`;
  }
  sel.innerHTML = opts;
  sel.dataset.populated = '1';
}
function syncDataLimiteAnoFromDate(){
  const sel = document.getElementById('fDataLimiteAno');
  const dataLimite = document.getElementById('fDataLimite').value;
  if(!sel) return;
  sel.value = dataLimite ? dataLimite.slice(0,4) : '';
}
function bindDataLimiteAno(){
  const sel = document.getElementById('fDataLimiteAno');
  const fPrazo = document.getElementById('fPrazoCorrente');
  if(fPrazo) fPrazo.addEventListener('input', ()=>{ fPrazo.dataset.userEdited = '1'; });
  const fPrazoInt = document.getElementById('fPrazoIntermediario');
  if(fPrazoInt) fPrazoInt.addEventListener('input', ()=>{ fPrazoInt.dataset.userEdited = '1'; });
  const fDest = document.getElementById('fDestinacao');
  if(fDest) fDest.addEventListener('change', ()=>{ fDest.dataset.userEdited = '1'; });
  if(!sel) return;
  populateDataLimiteAnoOptions();
  sel.addEventListener('change', ()=>{
    if(sel.value) document.getElementById('fDataLimite').value = `${sel.value}-12-31`;
  });
  document.getElementById('fDataLimite').addEventListener('change', syncDataLimiteAnoFromDate);
}

function bindAutocomplete(){
  const input = document.getElementById('fCodigo');
  const list = document.getElementById('acList');
  if(!input) return;
  input.addEventListener('input', ()=>{
    const q = input.value.toLowerCase().trim();
    updateTTDPreview();
    computeAndFillDataLimite();
    if(q.length<1){ list.style.display='none'; return; }
    const matches = TTD_ENTRIES.filter(e=> e.codigo.toLowerCase().includes(q) || e.descritor.toLowerCase().includes(q)).slice(0,30);
    if(!matches.length){ list.style.display='none'; return; }
    list.innerHTML = matches.map(m=>`<div data-code="${esc(m.codigo)}"><span class="ac-code">${esc(m.codigo)}</span>${esc(m.descritor)}</div>`).join('');
    list.style.display='block';
    list.querySelectorAll('div').forEach(d=>{
      d.addEventListener('click', ()=>{
        input.value = d.dataset.code;
        list.style.display='none';
        updateTTDPreview();
        computeAndFillDataLimite();
      });
    });
  });
  document.addEventListener('click', (e)=>{
    if(!list.contains(e.target) && e.target!==input) list.style.display='none';
  });
  document.getElementById('fDataRegistro').addEventListener('change', computeAndFillDataLimite);
}

/* ==================== OPERAÇÕES COM O BACKEND (GOOGLE SHEETS) ====================
   Importante: as requisições POST abaixo NÃO definem um header Content-Type
   customizado de propósito. Isso faz o navegador tratar a chamada como
   "simple request" (text/plain), evitando o preflight OPTIONS que o
   Google Apps Script não responde — essa é a causa mais comum de um
   backend no Apps Script "não funcionar" quando chamado de outro domínio
   (Netlify, GitHub Pages etc). O Code.gs lê o corpo bruto e faz JSON.parse. */
async function salvarFormulario(){
  const codigo = document.getElementById('fCodigo').value.trim();
  const entry = TTD_MAP[codigo.toUpperCase()];
  const rec = {
    id: editingId || ('r_' + Date.now().toString(36) + Math.random().toString(36).slice(2,7)),
    codigo,
    classificacao: entry ? entry.descritor : '',
    caixa: document.getElementById('fCaixa').value.trim(),
    processo: document.getElementById('fProcesso').value.trim(),
    referencia: document.getElementById('fReferencia').value.trim(),
    dataRegistro: document.getElementById('fDataRegistro').value,
    dataLimite: document.getElementById('fDataLimite').value,
    destinacao: document.getElementById('fDestinacao').value.trim() || (entry ? entry.destinacao : ''),
    localizacao: document.getElementById('fLocalizacao').value.trim(),
    estado: document.getElementById('fEstado').value,
    termo: document.getElementById('fTermo').value.trim(),
    prazoCorrente: document.getElementById('fPrazoCorrente').value.trim() || (entry ? entry.prazo_corrente : ''),
    prazoIntermediario: document.getElementById('fPrazoIntermediario').value.trim() || (entry ? entry.prazo_intermediario : '')
  };
  if(!rec.caixa && !rec.codigo){
    showToast('Informe ao menos o código e a caixa.');
    return;
  }

  showToast('Enviando para o servidor central…');
  try {
      const response = await fetch(CONFIG.API_URL, {
          method: 'POST',
          body: JSON.stringify({ action: 'salvarDocumento', documento: rec, token: localStorage.getItem('arquivista_token') || '' })
      });
      const data = await response.json();
      if(data.success) {
          await carregarDadosServidor();
          closeModal();
          showToast('Registro salvo no banco de dados!');
      } else if (data.sessaoInvalida) {
          showToast('Sua sessão expirou. Faça login novamente.');
          setTimeout(logout, 1500);
      } else {
          showToast('Erro: ' + (data.message||'não foi possível salvar.'));
      }
  } catch(e) {
      showToast('Erro crítico de conexão com o servidor.');
  }
}

async function deletarRegistro(){
  if(!editingId) return;
  if(!confirm('Excluir este registro definitivamente do banco de dados central?')) return;
  try {
      const response = await fetch(CONFIG.API_URL, {
          method: 'POST',
          body: JSON.stringify({ action: 'deletarDocumento', id: editingId, token: localStorage.getItem('arquivista_token') || '' })
      });
      const data = await response.json();
      if(data.success) {
          await carregarDadosServidor();
          closeModal();
          showToast('Registro excluído.');
      } else if (data.sessaoInvalida) {
          showToast('Sua sessão expirou. Faça login novamente.');
          setTimeout(logout, 1500);
      } else {
          showToast('Erro ao excluir: ' + (data.message||''));
      }
  } catch(e) {
      showToast('Erro ao excluir no servidor.');
  }
}

/* ==================== EXPORTAÇÃO XLSX ==================== */
const COLS = ['CAIXA','CÓDIGO','CLASSIFICAÇÃO','REFERÊNCIA DO DOCUMENTO','Nº PROCESSO/EPI','DATA-LIMITE',
  'PRAZO FASE CORRENTE','PRAZO FASE INTERMEDIÁRIA','DESTINAÇÃO FINAL','LOCALIZAÇÃO NO ARQUIVO DESLIZANTE',
  'ESTADO DE CONSERVAÇÃO','TERMO DE TRANSFERÊNCIA','DATA DO REGISTRO'];

function exportarParaExcel(){
  const data = [COLS];
  RECORDS.forEach(r=>{
    data.push([r.caixa, r.codigo, r.classificacao, r.referencia, r.processo, r.dataLimite,
      r.prazoCorrente, r.prazoIntermediario, r.destinacao, r.localizacao, r.estado, r.termo, r.dataRegistro]);
  });
  const ws = XLSX.utils.aoa_to_sheet(data);
  ws['!cols'] = COLS.map(()=>({wch:20}));
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'DOCUMENTOS');
  XLSX.writeFile(wb, `SGA_Acervo_Fiocruz_${new Date().toISOString().slice(0,10)}.xlsx`);
  showToast('Planilha exportada.');
}

/* ==================== UTILIDADES ==================== */
function esc(s){
  return String(s??'').replace(/[&<>"']/g, c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}
let toastTimer;
function showToast(msg){
  const t = document.getElementById('toast');
  if(!t) return;
  t.textContent = msg; t.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(()=>t.classList.remove('show'), 2800);
}
function switchView(name){
  document.querySelectorAll('.tab').forEach(t=>t.classList.toggle('active', t.dataset.view===name));
  document.querySelectorAll('.view').forEach(v=>v.classList.toggle('active', v.id==='view-'+name));
}
